1	import { describe, it, expect } from "vitest";
2	import { spawnSync } from "node:child_process";
3	import { fileURLToPath } from "node:url";
4	
5	// CLI integration tests: spawn src/cli.ts, write a JSON scenario to stdin,
6	// read the JSON results from stdout, and assert on the process exit code.
7	
8	const cliPath = fileURLToPath(new URL("./cli.ts", import.meta.url));
9	
10	function runCli(scenario: unknown): {
11	  status: number | null;
12	  stdout: string;
13	  stderr: string;
14	} {
15	  const result = spawnSync("npx", ["tsx", cliPath], {
16	    input: JSON.stringify(scenario),
17	    encoding: "utf8",
18	  });
19	  return {
20	    status: result.status,
21	    stdout: result.stdout,
22	    stderr: result.stderr,
23	  };
24	}
25	
26	describe("claim-office CLI (stdin -> stdout)", () => {
27	  it("should read a scenario from stdin and write a results JSON to stdout", () => {
28	    const scenario = {
29	      customer: { yearsWithMHPCO: 5 },
30	      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
31	    };
32	
33	    const { status, stdout } = runCli(scenario);
34	
35	    expect(status).toBe(0);
36	    const parsed = JSON.parse(stdout);
37	    expect(Array.isArray(parsed.results)).toBe(true);
38	  });
39	  it.todo(
40	    "should return one result per step, in the same order as the input steps",
41	  );
42	  it.todo(
43	    "should emit a quote result with a premium field for a quote step",
44	  );
45	  it.todo(
46	    "should emit a claim result with payout and remainingCap fields for a claim step",
47	  );
48	  it.todo(
49	    "should process the schema example (amulet quote then fire claim) end to end",
50	  );
51	
52	  describe("error exits (non-zero status, stderr, no results on stdout)", () => {
53	    it.todo("should exit non-zero for a quote with an unknown item type");
54	    it.todo(
55	      "should exit non-zero for a claim referencing an item not in the policy",
56	    );
57	    it.todo(
58	      "should exit non-zero for a claim with more damage entries than the policy covers",
59	    );
60	    it.todo("should exit non-zero for a claim with a negative damage amount");
61	  });
62	});
