1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	  moonstone: 25,
9	};
10	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
11	  sword: 1000,
12	  amulet: 600,
13	  staff: 800,
14	  potion: 400,
15	  rune: 250,
16	  moonstone: 250,
17	};
18	
19	type Item = {
20	  type: string;
21	  cursed?: boolean;
22	  enchantment?: number;
23	  material?: string;
24	};
25	type Customer = { years: number };
26	type Damage = { itemType: string; amount: number };
27	type Incident = { cause: string; damages: Damage[] };
28	type Step = {
29	  type: string;
30	  items?: Item[];
31	  customer?: Customer;
32	  policy?: number;
33	  incident?: Incident;
34	};
35	
36	const BLOCK_OF_3_PRICE = 60;
37	
38	const COMPONENT_TYPES = ["rune", "moonstone"];
39	
40	function countByType(items: Item[]): Record<string, number> {
41	  const counts: Record<string, number> = {};
42	  for (const item of items) {
43	    counts[item.type] = (counts[item.type] ?? 0) + 1;
44	  }
45	  return counts;
46	}
47	
48	function priceForType(type: string, count: number): number {
49	  if (COMPONENT_TYPES.includes(type) && count === 3) {
50	    return BLOCK_OF_3_PRICE;
51	  }
52	  return count * BASE_PREMIUM_BY_TYPE[type];
53	}
54	
55	function isHighlyEnchanted(item: Item): boolean {
56	  return (item.enchantment ?? 0) >= 5;
57	}
58	
59	function hasItemModifier(item: Item): boolean {
60	  return Boolean(item.cursed) || isHighlyEnchanted(item);
61	}
62	
63	const CURSE_SURCHARGE = 0.5;
64	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
65	
66	function itemSurcharge(item: Item): number {
67	  const base = BASE_PREMIUM_BY_TYPE[item.type];
68	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE : 0;
69	  const enchantmentSurcharge = isHighlyEnchanted(item)
70	    ? base * HIGH_ENCHANTMENT_SURCHARGE
71	    : 0;
72	  return curseSurcharge + enchantmentSurcharge;
73	}
74	
75	function modifiedItemsBasePremium(items: Item[]): number {
76	  return items
77	    .filter(hasItemModifier)
78	    .reduce((total, item) => total + BASE_PREMIUM_BY_TYPE[item.type], 0);
79	}
80	
81	function plainPremium(items: Item[]): number {
82	  const counts = countByType(items.filter((item) => !hasItemModifier(item)));
83	  return Object.entries(counts).reduce(
84	    (total, [type, count]) => total + priceForType(type, count),
85	    0,
86	  );
87	}
88	
89	function basePremium(items: Item[]): number {
90	  return modifiedItemsBasePremium(items) + plainPremium(items);
91	}
92	
93	function surchargePremium(items: Item[]): number {
94	  return items.reduce((total, item) => total + itemSurcharge(item), 0);
95	}
96	
97	const LOYALTY_DISCOUNT = 0.2;
98	const LOYALTY_MIN_YEARS = 2;
99	const FIRST_INSURANCE_SURCHARGE = 0.1;
100	const FOLLOW_UP_DISCOUNT = 0.15;
101	
102	function isLoyal(customer: Customer): boolean {
103	  return customer.years >= LOYALTY_MIN_YEARS;
104	}
105	
106	function policyPremium(step: Step, isFollowUp: boolean): number {
107	  const items = step.items ?? [];
108	  const base = basePremium(items);
109	  const surcharges = surchargePremium(items);
110	  if (step.customer === undefined) {
111	    return base + surcharges;
112	  }
113	  const loyaltyDiscount = isLoyal(step.customer) ? LOYALTY_DISCOUNT : 0;
114	  const followUpDiscount = isFollowUp ? FOLLOW_UP_DISCOUNT : 0;
115	  const netModifierRate =
116	    FIRST_INSURANCE_SURCHARGE - loyaltyDiscount - followUpDiscount;
117	  return base + surcharges + base * netModifierRate;
118	}
119	
120	function roundUpInFavor(amount: number): number {
121	  return Math.ceil(amount);
122	}
123	
124	function roundDownInFavor(amount: number): number {
125	  return Math.floor(amount);
126	}
127	
128	const DEDUCTIBLE = 100;
129	const CAP_MULTIPLIER = 2;
130	const HIGH_ENCHANTMENT_THRESHOLD = 8;
131	const HIGH_ENCHANTMENT_REIMBURSEMENT = 0.5;
132	
133	function insuranceSum(items: Item[]): number {
134	  return items.reduce(
135	    (total, item) => total + INSURANCE_VALUE_BY_TYPE[item.type],
136	    0,
137	  );
138	}
139	
140	function assertKnownItemTypes(items: Item[]): void {
141	  for (const item of items) {
142	    if (!(item.type in BASE_PREMIUM_BY_TYPE)) {
143	      throw new Error(`Unknown item type: ${item.type}`);
144	    }
145	  }
146	}
147	
148	function quoteResult(step: Step, isFollowUp: boolean): { premium: number } {
149	  assertKnownItemTypes(step.items ?? []);
150	  return {
151	    premium: roundUpInFavor(PROCESSING_FEE + policyPremium(step, isFollowUp)),
152	  };
153	}
154	
155	function damagePayout(item: Item | undefined, amount: number): number {
156	  const coveredAmount =
157	    (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
158	      ? amount * HIGH_ENCHANTMENT_REIMBURSEMENT
159	      : amount;
160	  return coveredAmount - DEDUCTIBLE;
161	}
162	
163	function assertValidDamages(damages: Damage[], policyItems: Item[]): void {
164	  for (const damage of damages) {
165	    if (damage.amount < 0) {
166	      throw new Error(`Invalid damage amount: ${damage.amount}`);
167	    }
168	  }
169	  const insuredCounts = countByType(policyItems);
170	  const damageCounts = countByType(
171	    damages.map((damage) => ({ type: damage.itemType })),
172	  );
173	  for (const [type, count] of Object.entries(damageCounts)) {
174	    if (count > (insuredCounts[type] ?? 0)) {
175	      throw new Error(`Too many damage entries for ${type}`);
176	    }
177	  }
178	}
179	
180	function claimResult(
181	  step: Step,
182	  steps: Step[],
183	  consumedByPolicy: Map<number, number>,
184	): { payout: number; remainingCap: number } {
185	  const policyIndex = step.policy ?? 0;
186	  const policyStep = steps[policyIndex];
187	  const policyItems = policyStep.items ?? [];
188	  const cap = CAP_MULTIPLIER * insuranceSum(policyItems);
189	  const damages = step.incident?.damages ?? [];
190	  assertValidDamages(damages, policyItems);
191	  const desiredPayout = damages.reduce((total, damage) => {
192	    const item = policyItems.find((i) => i.type === damage.itemType);
193	    return total + damagePayout(item, damage.amount);
194	  }, 0);
195	  const consumed = consumedByPolicy.get(policyIndex) ?? 0;
196	  const availableCap = cap - consumed;
197	  const payout = roundDownInFavor(Math.min(desiredPayout, availableCap));
198	  consumedByPolicy.set(policyIndex, consumed + payout);
199	  return { payout, remainingCap: availableCap - payout };
200	}
201	
202	function hasPriorQuote(steps: Step[], index: number): boolean {
203	  return steps.slice(0, index).some((prior) => prior.type === "quote");
204	}
205	
206	export function runScenario(steps: Step[]): unknown[] {
207	  const consumedByPolicy = new Map<number, number>();
208	  return steps.map((step, index) => {
209	    if (step.type === "claim") {
210	      return claimResult(step, steps, consumedByPolicy);
211	    }
212	    return quoteResult(step, hasPriorQuote(steps, index));
213	  });
214	}
